mapper.select:
select LOT_CODE
from ITEM_LOT
where ITEM_ID = #{itemId}

SELECT ITEM.ITEM_CODE, PURCHASE_ARRIVAL_D.ITEM_DESCRIPTION, SUM(PURCHASE_ARRIVAL_D.ACCEPTED_BUSINESS_QTY + PURCHASE_ARRIVAL_D.SP_RECEIPT_BUSINESS_QTY - PURCHASE_ARRIVAL_D.RECEIPTED_BUSINESS_QTY) AS APPLY_QTY, PURCHASE_ARRIVAL_D.ITEM_SPECIFICATION, PURCHASE_ARRIVAL.DOC_NO, SUPPLIER.SUPPLIER_NAME, CONVERT(CHAR(8), PURCHASE_ARRIVAL.DOC_DATE, 112) AS DOC_DATE, UNIT.UNIT_CODE
FROM PURCHASE_ARRIVAL LEFT JOIN SUPPLIER ON PURCHASE_ARRIVAL.SUPPLIER_ID = SUPPLIER.SUPPLIER_BUSINESS_ID LEFT JOIN PLANT ON PURCHASE_ARRIVAL.RECEIVE_Owner_Org_ROid = PLANT.PLANT_ID LEFT JOIN PURCHASE_ARRIVAL_D ON PURCHASE_ARRIVAL.PURCHASE_ARRIVAL_ID = PURCHASE_ARRIVAL_D.PURCHASE_ARRIVAL_ID LEFT JOIN ITEM ON PURCHASE_ARRIVAL_D.ITEM_ID = ITEM.ITEM_BUSINESS_ID LEFT JOIN BIN ON PURCHASE_ARRIVAL_D.BIN_ID = BIN.BIN_ID LEFT JOIN WAREHOUSE ON PURCHASE_ARRIVAL_D.WAREHOUSE_ID = WAREHOUSE.WAREHOUSE_ID LEFT JOIN UNIT ON PURCHASE_ARRIVAL_D.BUSINESS_UNIT_ID = UNIT.UNIT_ID WHERE PURCHASE_ARRIVAL.DOC_NO = #{docNo}
GROUP BY PURCHASE_ARRIVAL.DOC_NO , PURCHASE_ARRIVAL.DOC_DATE , SUPPLIER.SUPPLIER_NAME , ITEM.ITEM_CODE , PURCHASE_ARRIVAL_D.ITEM_DESCRIPTION , PURCHASE_ARRIVAL_D.ITEM_SPECIFICATION , UNIT.UNIT_CODE

SELECT TOP 100 PURCHASE_ARRIVAL.DOC_NO, CONVERT(CHAR(8), PURCHASE_ARRIVAL.DOC_DATE, 112) AS DOC_DATE, SUPPLIER.SUPPLIER_NAME, SUPPLIER.SUPPLIER_CODE, ITEM.ITEM_CODE, PURCHASE_ARRIVAL_D.SequenceNumber as xh, PURCHASE_ARRIVAL_D.ITEM_DESCRIPTION, PURCHASE_ARRIVAL_D.ITEM_SPECIFICATION, SUM(PURCHASE_ARRIVAL_D.ACCEPTED_BUSINESS_QTY + PURCHASE_ARRIVAL_D.SP_RECEIPT_BUSINESS_QTY - PURCHASE_ARRIVAL_D.RECEIPTED_BUSINESS_QTY) AS applyQty, WAREHOUSE.WAREHOUSE_CODE, WAREHOUSE.WAREHOUSE_NAME, BIN.BIN_CODE, BIN.BIN_NAME, UNIT.UNIT_CODE, CAST(PURCHASE_ARRIVAL_D.INSPECTED_QTY AS REAL) AS checkQty, PO_QC_RESULT.REMARK as remark, PURCHASE_ARRIVAL_D.PRICE_QTY-PURCHASE_ARRIVAL_D.INSPECTED_QTY AS pendingCheckQty, PURCHASE_ARRIVAL_D.INSPECTION_STATUS as checkStatus FROM PURCHASE_ARRIVAL LEFT JOIN SUPPLIER ON PURCHASE_ARRIVAL.SUPPLIER_ID = SUPPLIER.SUPPLIER_BUSINESS_ID LEFT JOIN PLANT ON PURCHASE_ARRIVAL.RECEIVE_Owner_Org_ROid = PLANT.PLANT_ID LEFT JOIN PURCHASE_ARRIVAL_D ON PURCHASE_ARRIVAL.PURCHASE_ARRIVAL_ID = PURCHASE_ARRIVAL_D.PURCHASE_ARRIVAL_ID LEFT JOIN ITEM ON PURCHASE_ARRIVAL_D.ITEM_ID = ITEM.ITEM_BUSINESS_ID LEFT JOIN BIN ON PURCHASE_ARRIVAL_D.BIN_ID = BIN.BIN_ID LEFT JOIN WAREHOUSE ON PURCHASE_ARRIVAL_D.WAREHOUSE_ID = WAREHOUSE.WAREHOUSE_ID LEFT JOIN UNIT ON PURCHASE_ARRIVAL_D.BUSINESS_UNIT_ID = UNIT.UNIT_ID LEFT JOIN PO_QC_RESULT ON PURCHASE_ARRIVAL_D.PURCHASE_ARRIVAL_D_ID = PO_QC_RESULT.SOURCE_ID_ROid LEFT JOIN PO_QC_RESULT_D ON PO_QC_RESULT.PO_QC_RESULT_ID = PO_QC_RESULT_D.PO_QC_RESULT_ID WHERE PURCHASE_ARRIVAL.CATEGORY = N'37'
and PURCHASE_ARRIVAL.DOC_NO like concat('%',#{docNo},'%')
and PURCHASE_ARRIVAL.DOC_DATE >= #{startDate}
and PURCHASE_ARRIVAL.DOC_DATE <= #{endDate}
and (PURCHASE_ARRIVAL_D.INSPECTION_STATUS = '2' OR PURCHASE_ARRIVAL_D.INSPECTION_STATUS = '3')
GROUP BY PURCHASE_ARRIVAL.DOC_NO , PURCHASE_ARRIVAL.DOC_DATE , SUPPLIER.SUPPLIER_CODE , SUPPLIER.SUPPLIER_NAME , ITEM.ITEM_CODE , PURCHASE_ARRIVAL_D.ITEM_DESCRIPTION , PURCHASE_ARRIVAL_D.ITEM_SPECIFICATION , WAREHOUSE.WAREHOUSE_CODE , WAREHOUSE.WAREHOUSE_NAME , BIN.BIN_CODE , BIN.BIN_NAME , UNIT.UNIT_CODE , PURCHASE_ARRIVAL_D.SequenceNumber, PO_QC_RESULT_D.QUALIFIED_BUSINESS_QTY, PO_QC_RESULT.REMARK , PO_QC_RESULT_D.UNQUALIFIED_BUSINESS_QTY, PO_QC_RESULT_D.IN_DESTROYED_BUSINESS_QTY , PURCHASE_ARRIVAL_D.INSPECTED_QTY ,PURCHASE_ARRIVAL_D.PRICE_QTY ,PURCHASE_ARRIVAL_D.INSPECTION_STATUS

SELECT DISTINCT PURCHASE_ARRIVAL.DOC_NO AS docNo, CONVERT(CHAR(8), PURCHASE_ARRIVAL.DOC_DATE, 112) AS docDate, SUPPLIER.SUPPLIER_NAME AS supplierName, SUPPLIER.SUPPLIER_CODE AS supplierCode FROM PURCHASE_ARRIVAL LEFT JOIN SUPPLIER ON PURCHASE_ARRIVAL.SUPPLIER_ID = SUPPLIER.SUPPLIER_BUSINESS_ID LEFT JOIN PLANT ON PURCHASE_ARRIVAL.RECEIVE_Owner_Org_ROid = PLANT.PLANT_ID LEFT JOIN PURCHASE_ARRIVAL_D ON PURCHASE_ARRIVAL.PURCHASE_ARRIVAL_ID = PURCHASE_ARRIVAL_D.PURCHASE_ARRIVAL_ID LEFT JOIN ITEM ON PURCHASE_ARRIVAL_D.ITEM_ID = ITEM.ITEM_BUSINESS_ID
where PURCHASE_ARRIVAL.DOC_NO like concat('%', #{docNo}, '%') and SUPPLIER.SUPPLIER_CODE like concat('%', #{supplierCode}, '%') AND ITEM.ITEM_CODE like concat('%', #{barCode}, '%') and PURCHASE_ARRIVAL.CATEGORY = N'36'
AND CAST(PURCHASE_ARRIVAL.DOC_DATE AS NVARCHAR(10)) > #{startDate}
AND CAST(PURCHASE_ARRIVAL.DOC_DATE AS NVARCHAR(10)) < #{endDate}

SELECT A.UDF001 defectRepairQty, A.UDF025 defectNumReason, (SELECT TOP 1 UDF021 FROM PURCHASE_ORDER_D WHERE PURCHASE_ORDER_ID = C.PURCHASE_ORDER_ID) customerNum, A.PO_ARRIVAL_INSPECTION_ID inspectionUuid, PLANT.PLANT_CODE AS plantCode, DOC.DOC_NAME AS checkName, A.DOC_NO AS checkDocNo, D.DOC_NO AS arrivalDocNo, C.PURCHASE_ARRIVAL_D_ID AS arrivalDUuid, C.SequenceNumber AS arrivalDSequenceNumber, SUPPLIER.SUPPLIER_CODE AS supplierCode, SUPPLIER.SUPPLIER_NAME AS supplierName, ADMIN_UNIT.ADMIN_UNIT_NAME AS departmentName, EMPLOYEE.EMPLOYEE_NAME AS employeeName, D.SUPPLIER_ORDER_NO AS receiptNo, CONVERT(varchar(10), CONVERT(datetime, A.CreateDate), 120) AS createDate, CONVERT(varchar(10), CONVERT(datetime, D.DOC_DATE), 120) AS receiptDate, ITEM.ITEM_CODE AS itemCode, C.ITEM_DESCRIPTION AS itemName, C.ITEM_SPECIFICATION AS itemSpec, ITEM_FEATURE.ITEM_FEATURE_ID AS itemFeatureId, ITEM_LOT.LOT_CODE AS lotCode, ITEM_LOT.LOT_DESCRIPTION AS lotDescription, ITEM_LOT.EFFECTIVE_DATE AS effectiveDate, ITEM_LOT.INEFFECTIVE_DATE AS ineffectiveDate, A.INSPECTION_QTY AS inspectionQty, A.STRICTNESS_DEGREE AS strictnessDegree, A.ACCEPTABLE_QTY AS acceptableQty, A.UNQUALIFIED_QTY AS unqualifiedQty, A.DESTROYED_QTY AS destroyedQty, A.DECISION AS decision, A.REINSPECTION AS reinspection, A.RESULT_STATUS AS resultStatus, A.DECISION_DESCRIPTION AS decisionDescription, CASE WHEN A.UDF026 IS NULL OR A.UDF026 = '' THEN 'true' ELSE A.UDF026 END AS UDF026 FROM PO_ARRIVAL_INSPECTION AS A LEFT JOIN PO_ARRIVAL_INSPECTION_D AS B ON B.PO_ARRIVAL_INSPECTION_D_ID = A.PO_ARRIVAL_INSPECTION_ID LEFT JOIN PURCHASE_ARRIVAL_D AS C ON C.PURCHASE_ARRIVAL_D_ID = A.SOURCE_ID LEFT JOIN PURCHASE_ARRIVAL AS D ON D.PURCHASE_ARRIVAL_ID = C.PURCHASE_ARRIVAL_ID LEFT JOIN SUPPLIER ON SUPPLIER.SUPPLIER_BUSINESS_ID = D.SUPPLIER_ID LEFT JOIN ITEM ON ITEM.ITEM_BUSINESS_ID = C.ITEM_ID LEFT JOIN UNIT ON UNIT.UNIT_ID = C.BUSINESS_UNIT_ID LEFT JOIN PLANT ON PLANT.PLANT_ID = A.Owner_Org_ROid LEFT JOIN DOC ON DOC.DOC_ID = A.DOC_ID LEFT JOIN ITEM_FEATURE ON ITEM_FEATURE.ITEM_FEATURE_ID = A.ITEM_FEATURE_ID LEFT JOIN ITEM_LOT ON ITEM_LOT.ITEM_LOT_ID = A.ITEM_LOT_ID LEFT JOIN INSPECTION_ITEM ON INSPECTION_ITEM.INSPECTION_ITEM_ID = B.INSPECTION_ITEM_ID LEFT JOIN DEFECTIVE_REASONS ON DEFECTIVE_REASONS.DEFECTIVE_REASONS_ID = B.DEFECTIVE_REASONS_ID LEFT OUTER JOIN ADMIN_UNIT ON ADMIN_UNIT.ADMIN_UNIT_ID = A.Owner_Dept LEFT OUTER JOIN EMPLOYEE ON EMPLOYEE.EMPLOYEE_ID = A.Owner_Emp
D.DOC_NO = #{arrivalDocNo}
AND ITEM.ITEM_CODE = #{itemCode}
AND A.DOC_NO = #{checkDocNo}

SELECT A.CreateDate, RESULT_STATUS, A.PO_ARRIVAL_INSPECTION_ID inspectionUuid, PLANT.PLANT_CODE AS plantCode, DOC.DOC_NAME AS checkName, A.DOC_NO AS checkDocNo, D.DOC_NO AS arrivalDocNo, C.PURCHASE_ARRIVAL_D_ID AS arrivalDUuid, C.SequenceNumber AS arrivalDSequenceNumber, SUPPLIER.SUPPLIER_CODE AS supplierCode, SUPPLIER.SUPPLIER_NAME AS supplierName, ADMIN_UNIT.ADMIN_UNIT_NAME AS departmentName, EMPLOYEE.EMPLOYEE_NAME AS employeeName, D.SUPPLIER_ORDER_NO AS receiptNo, CONVERT(varchar(10), CONVERT(datetime, A.CreateDate), 120) AS createDate, CONVERT(varchar(10), CONVERT(datetime, D.DOC_DATE), 120) AS receiptDate, ITEM.ITEM_CODE AS itemCode, C.ITEM_DESCRIPTION AS itemName, C.ITEM_SPECIFICATION AS itemSpec, ITEM_FEATURE.ITEM_FEATURE_ID AS itemFeatureId, ITEM_LOT.LOT_CODE AS lotCode, ITEM_LOT.LOT_DESCRIPTION AS lotDescription, ITEM_LOT.EFFECTIVE_DATE AS effectiveDate, ITEM_LOT.INEFFECTIVE_DATE AS ineffectiveDate, A.STRICTNESS_DEGREE AS strictnessDegree, A.INSPECTION_QTY AS inspectionQty, A.ACCEPTABLE_QTY AS acceptableQty, A.UNQUALIFIED_QTY AS unqualifiedQty, A.DESTROYED_QTY AS destroyedQty, A.DECISION AS decision, A.REINSPECTION AS reinspection, A.RESULT_STATUS AS resultStatus, A.DECISION_DESCRIPTION AS decisionDescription, Y.UDF021 customerNum, CASE WHEN A.UDF026 IS NULL OR A.UDF026 = '' THEN 'false' ELSE A.UDF026 END AS UDF026 FROM PO_ARRIVAL_INSPECTION AS A LEFT JOIN PO_ARRIVAL_INSPECTION_D AS B ON B.PO_ARRIVAL_INSPECTION_D_ID = A.PO_ARRIVAL_INSPECTION_ID LEFT JOIN PURCHASE_ARRIVAL_D AS C ON C.PURCHASE_ARRIVAL_D_ID = A.SOURCE_ID LEFT JOIN PURCHASE_ARRIVAL AS D ON D.PURCHASE_ARRIVAL_ID = C.PURCHASE_ARRIVAL_ID LEFT JOIN PURCHASE_ORDER_SD Z ON Z.PURCHASE_ORDER_SD_ID=C.SOURCE_ID_ROid LEFT JOIN PURCHASE_ORDER_D Y ON Y.PURCHASE_ORDER_D_ID=Z.PURCHASE_ORDER_D_ID LEFT JOIN PURCHASE_ORDER E ON E.PURCHASE_ORDER_ID =Y.PURCHASE_ORDER_ID LEFT JOIN SUPPLIER ON SUPPLIER.SUPPLIER_BUSINESS_ID = D.SUPPLIER_ID LEFT JOIN ITEM ON ITEM.ITEM_BUSINESS_ID = C.ITEM_ID LEFT JOIN UNIT ON UNIT.UNIT_ID = C.BUSINESS_UNIT_ID LEFT JOIN PLANT ON PLANT.PLANT_ID = A.Owner_Org_ROid LEFT JOIN DOC ON DOC.DOC_ID = A.DOC_ID LEFT JOIN ITEM_FEATURE ON ITEM_FEATURE.ITEM_FEATURE_ID = A.ITEM_FEATURE_ID LEFT JOIN ITEM_LOT ON ITEM_LOT.ITEM_LOT_ID = A.ITEM_LOT_ID LEFT JOIN INSPECTION_ITEM ON INSPECTION_ITEM.INSPECTION_ITEM_ID = B.INSPECTION_ITEM_ID LEFT JOIN DEFECTIVE_REASONS ON DEFECTIVE_REASONS.DEFECTIVE_REASONS_ID = B.DEFECTIVE_REASONS_ID LEFT OUTER JOIN ADMIN_UNIT ON ADMIN_UNIT.ADMIN_UNIT_ID = A.Owner_Dept LEFT OUTER JOIN EMPLOYEE ON EMPLOYEE.EMPLOYEE_ID = A.Owner_Emp WHERE
A.RESULT_STATUS IN
#{status}
AND CONVERT(varchar(10), CONVERT(datetime, A.CreateDate), 120) BETWEEN #{dto.start} AND #{dto.end}
AND PLANT.PLANT_CODE = #{dto.shjg}
AND SUPPLIER.SUPPLIER_NAME LIKE CONCAT('%', #{dto.supplierName}, '%')
AND DOC.DOC_NAME LIKE CONCAT('%', #{dto.checkName}, '%')
AND A.DOC_NO LIKE CONCAT('%', #{dto.checkDocNo}, '%')
AND D.DOC_NO LIKE CONCAT('%', #{dto.arrivalDocNo}, '%')

SELECT DOC_NO deliveryNo,FORMAT(DOC_DATE, 'yyyy-MM-dd') deliveryDate,SUPPLIER_FULL_NAME supplierName,SUPPLIER_ADDR_NAME
FROM PURCHASE_ARRIVAL
WHERE DOC_NO = #{docNo}

SELECT DISTINCT A.DOC_NO arrivalNo, C.UDF021 customerNum, SUPPLIER.SUPPLIER_CODE AS supplierCode, SUPPLIER.SUPPLIER_NAME AS supplierName, B.INSPECTION_STATUS inspectionStatus, CONVERT ( VARCHAR ( 10 ), CONVERT ( datetime, A.DOC_DATE ), 120 ) AS docDate FROM PURCHASE_ARRIVAL A LEFT JOIN PURCHASE_ARRIVAL_D B ON A.PURCHASE_ARRIVAL_ID = B.PURCHASE_ARRIVAL_ID LEFT JOIN PURCHASE_ORDER_D C ON C.PURCHASE_ORDER_ID = B.PURCHASE_ORDER_ID LEFT JOIN SUPPLIER ON SUPPLIER.SUPPLIER_BUSINESS_ID = A.SUPPLIER_ID LEFT JOIN ITEM ON ITEM.ITEM_BUSINESS_ID = B.ITEM_ID LEFT JOIN UNIT ON UNIT.UNIT_ID = B.BUSINESS_UNIT_ID
AND CONVERT(varchar(10), CONVERT(datetime, A.CreateDate), 120) BETWEEN #{start} AND #{end}
AND B.INSPECTION_STATUS = #{inspectionStatus}
AND B.RECEIPT_CLOSE = #{receiptClose}
ORDER BY A.DOC_DATE DESC

SELECT A.barcode FROM bm_barcode_detail A
LEFT JOIN bm_barcode_detail B on B.standard_col10 = A.id
WHERE A.bar_type = 5 AND B.barcode = #{barcode}

SELECT DISTINCT A.DOC_NO arrivalNo, SUPPLIER.SUPPLIER_CODE AS supplierCode, SUPPLIER.SUPPLIER_NAME AS supplierName, CONVERT ( VARCHAR ( 10 ), CONVERT ( datetime, A.DOC_DATE ), 120 ) AS docDate FROM PURCHASE_ARRIVAL A LEFT JOIN SUPPLIER ON SUPPLIER.SUPPLIER_BUSINESS_ID = A.SUPPLIER_ID WHERE A.PURCHASE_ARRIVAL_ID IN (SELECT PURCHASE_ARRIVAL_ID FROM PURCHASE_ARRIVAL_D WHERE INSPECTION_STATUS = '4' AND RECEIPT_CLOSE = '0' )
AND CONVERT(varchar(10), CONVERT(datetime, A.CreateDate), 120) BETWEEN #{start} AND #{end}
ORDER BY CONVERT ( VARCHAR ( 10 ), CONVERT ( datetime, A.DOC_DATE ), 120 ) DESC

SELECT DISTINCT D.parentId, bar_type, Z.UDF003 containerQty, Z.UDF024 containerName, CAST(CAST(Z.LONG AS FLOAT) AS VARCHAR(20)) + '*' + CAST(CAST(Z.HIGH AS FLOAT) AS VARCHAR(20)) + '*' + CAST(CAST(Z.WIDE AS FLOAT) AS VARCHAR(20)) AS containerDetail, D.purchaseOrder, deliveryNumber, purchaseOrder docNo, ISNULL(lot_att04,'') arrivalNo, ISNULL(lot_att30,'') lot_att30, FORMAT(create_date, 'yyyyMMdd') docDate, vendorCode supplierNo, delivery supplierName, item_no itemCode, M.ITEM_NAME itemName, M.ITEM_SPECIFICATION itemSpec, W.WAREHOUSE_CODE warehouseCode, ISNULL(Z.UDF021,'') binCode, qty matchQty, barcode, B.UDF021 customerNo, bm_barcode_detail.unit_no unitCode, bm_barcode_detail.unit_name unitName, consignee shjg FROM bm_barcode_detail LEFT JOIN deliveryNoteDetails D ON source_no = D.uuid LEFT JOIN PURCHASE_ORDER A ON D.purchaseOrder LIKE CONCAT(A.DOC_NO, '-', '%') LEFT JOIN PURCHASE_ORDER_D B ON D.purchaseOrder = CONCAT(A.DOC_NO, '-', B.SequenceNumber) AND A.PURCHASE_ORDER_ID = B.PURCHASE_ORDER_ID LEFT JOIN ITEM M ON B.ITEM_ID = M.ITEM_BUSINESS_ID LEFT JOIN ITEM_PLANT Z ON Z.ITEM_ID = M.ITEM_BUSINESS_ID AND A.REV_ORG_SOURCE_ID_ROid=Z.Owner_Org_ROid LEFT JOIN UNIT U ON B.BUSINESS_UNIT_ID = UNIT_ID LEFT JOIN PURCHASE_ORDER_SD SD ON B.PURCHASE_ORDER_D_ID = SD.PURCHASE_ORDER_D_ID LEFT JOIN WAREHOUSE W ON SD.WAREHOUSE_ID = W.WAREHOUSE_ID LEFT JOIN BIN ON BIN.WAREHOUSE_ID = W.WAREHOUSE_ID LEFT JOIN SUPPLIER S ON A.SUPPLIER_ID = S.SUPPLIER_BUSINESS_ID LEFT JOIN deliveryList SS ON SS.uuid = D.parentId WHERE 1=1 AND lot_att30 IS NULL
and barcode = #{number}
ORDER BY item_no

update.foreach:
UPDATE bm_barcode_detail
SET lot_att04 = #{item.docNo}
WHERE barcode = #{item.barcode}

UPDATE bm_barcode_detail
SET lot_att30 = '2'
WHERE barcode = #{item}

mapper.update:
UPDATE bm_barcode_detail
SET lot_att08 = #{lotatt08},
    lot_att30 = #{lotatt30}
WHERE barcode IN

    #{barcode}

UPDATE bm_barcode_detail
SET lot_att30 = '1', lot_att31 ='2', lot_att04 = #{docNo}
WHERE barcode = #{barcode}

update bm_barcode_detail
set lot_att31 = '1'
where barcode = #{barcode}

UPDATE deliveryNoteDetails
SET arrivalNo = #{docNo}
WHERE uuid = (
    SELECT DISTINCT source_no FROM bm_barcode_detail WHERE barcode = #{barcode}
)

UPDATE PO_ARRIVAL_INSPECTION
SET CreateBy = #{createBy}, ModifiedBy = #{createBy}, LastModifiedBy = #{createBy}, ApproveBy = #{createBy}
WHERE DOC_NO = #{docNo}
